using Microsoft.AspNetCore.Http;
using System.Net.Http;
using System.Threading.Tasks;

public class WebhookProxy
{
    private readonly HttpClient _httpClient;

    public WebhookProxy(HttpClient httpClient)
    {
        _httpClient = httpClient;
    }

    public async Task<IActionResult> ForwardRequest(HttpRequest request)
    {
        string targetUrl = request.Headers["Target-Url"];

        if (string.IsNullOrEmpty(targetUrl))
        {
            return BadRequest("Target-Url header is missing.");
        }

        HttpResponseMessage response = await _httpClient.GetAsync(targetUrl);

        return new ContentResult
        {
            StatusCode = (int)response.StatusCode,
            Content = await response.Content.ReadAsStringAsync(),
        };
    }
}